#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5;

int t,n,m,d[N];
bool del[N];
vector<int> g[N];

int main(){
    scanf("%d",&t);
    while(t--){
        scanf("%d%d",&n,&m);
        for(int i=1;i<=n;i++)
            d[i]=del[i]=0,g[i].clear();
        for(int i=1,u,v;i<n;i++){
            scanf("%d%d",&u,&v);
            g[u].push_back(v);
            g[v].push_back(u);
            d[u]++,d[v]++;
        }
        queue<int> q,s;
        for(int i=1;i<=n;i++)
            if(d[i]<=1)
                q.push(i);
        int u=q.front(),cnt=n;
        q.pop();
        while(cnt>1){
            printf("? %d\n",u);
            fflush(stdout);
            int op,dist;
            scanf("%d",&op);
            if(op==-1)
                return 0;
            if(op==1){
                while(q.size()){
                    int x=q.front();
                    del[x]=1,cnt--;
                    q.pop();
                    for(int y:g[x])
                        if(--d[y]==1 && !del[y])
                            s.push(y);
                }
                while(s.size())
                    q.push(s.front()),s.pop();
            }else{
                scanf("%d",&dist);
                if(!dist)
                    break;
                del[u]=1;
                cnt--;
                for(int y:g[u])
                    if(--d[y]<=1 && !del[y])
                        q.push(y);
                u=q.front();
                q.pop();
            }
        }
        printf("! %d\n",u);
        fflush(stdout);
        int op;
        scanf("%d",&op);
        if(!op)
            return 0;
    }
    return 0;
}
